var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"저 쪽에서 총소리가 들렸습니다! 모두 조심하세요!","JPN":"向こうから銃声が聞こえました！　皆さん気を付けてください！","ENG":"I heard a gunshot from over there! Everyone, be careful!","TWN":"那邊傳出槍聲！大家小心！"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"음? 잠깐, 저 사람은 를르슈잖아?","JPN":"うん？　待って、あれはルルーシュ？","ENG":"Hmm? Hold on, isn't that Lelouch?","TWN":"嗯？那個人，不是魯路修嗎？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그리고…… 저건 타피르……?","JPN":"それに、あれはタピルなの？","ENG":"And also... Tapir...?","TWN":"另一個是……達爾……？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"뭐…… 타피르 선배? 그 눈은 뭐야……?","JPN":"えっ……、タピル先輩？　その目はなに……？","ENG":"Huh...? Tapir? What happened to your eyes...?","TWN":"什麼……達爾前輩？他的眼睛怎麼……？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이게 무슨 일이야? 도대체 뭐가 어떻게 돌아가는 건데?","JPN":"これはどういうこと？　いったい何が起きてるっていうの！？","ENG":"What just happened? What's going on here?","TWN":"怎麼會這樣？到底發生什麼事？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"대단하군요. 를르슈.","JPN":"すごいですね、ルルーシュ。","ENG":"Impressive, Lelouch.","TWN":"算你厲害，魯路修。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"분명, 수없이 기억이 리셋됐을 텐데 어떻게 제 정체를 간파해낸 거죠?","JPN":"数え切れないほど記憶がリセットされたはずなのに、\\nどうして僕の正体を見抜けたのですか？","ENG":"I'm certain your memory was reset countless times. How did you manage to figure out it was me?","TWN":"我明明就有重置過好幾次記憶，你是怎麼識破我的？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"말하지 않았나. 처음부터 이 세계 자체가 거짓이었다는 걸 눈치채고 있었다고.","JPN":"言っただろう。最初から、この世界自体が偽物だということに気づいていたと。","ENG":"Didn't I say? I knew this world was a lie from the start.","TWN":"我沒說嗎？我打從一開始就知道這個世界是假的。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"그러니까, 나에게 필요한 건 정보였어. 이레귤러를 구분할 수 있는 정보.","JPN":"だから、俺に必要なのは情報だった。イレギュラーを見分ける情報だ。","ENG":"That's why I needed to gather information. To sniff out the Irregular.","TWN":"所以我需要的是資訊，可以分辨不規律的資訊。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"이레귤러……!?","JPN":"イレギュラー……！？","ENG":"The Irregular...?!","TWN":"不規律……！？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그렇구나, 그래서 를르슈는 나한테 그런 쪽지를…….","JPN":"なるほど、だからルルーシュは私にあのメモを……","ENG":"Now I get it. That's why you left me that note...","TWN":"原來是這樣，所以你才會給我那張紙條……"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"그래, 유미나. 간단히 말해서, 이건 일종의 편 가르기야.","JPN":"そうだ、ミナ。簡単に言えば、これは一種の仲間分けだ。","ENG":"Yes, Yoo Mina. To put it simply, I was distinguishing friend from foe.","TWN":"沒錯，劉米娜。簡單來說，我在分類。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"타피르가 어떤 방법으로 우리들에게 거짓 기억을 심었는지는 몰라. 하지만 녀석이 심어둔 기억과 우리들의 원래 기억은 차이가 있지.","JPN":"やつがどんな方法で俺たちに偽りの記憶を植え付けたのかはわからない。\\nしかし、タピルが仕込んだ設定と俺たちの本来の記憶にはズレがある。","ENG":"I don't know how Tapir planted false memories in our minds. But those memories and our original ones are different.","TWN":"雖然不知道達爾是用什麼方法植入假記憶的，但他植入的記憶和我們原本的記憶，一定多少有落差。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"녀석이 심은 기억에서는 우리 모두 사이좋은 애쉬포드 학원의 학생회 멤버……라고 설정되어 있어.","JPN":"タピルが作り上げた設定で、俺たちはみんな、\\n仲が良いアッシュフォード学園の生徒会メンバー、ということになった。","ENG":"The planted memories state... that we are all good friends of the Student Council at Ashford Academy.","TWN":"在他植入的記憶中，設定我們是一群感情很好的阿什弗德學院學生會成員……。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"하지만 이 중에 진짜 애쉬포드 학생회 멤버는 나와 셜리 그리고 카렌 뿐이야.","JPN":"しかし、この中に本物の生徒会メンバーは\\n俺とシャーリー、そしてカレンしかいない。","ENG":"But the real Ashford Student Council members are me, Shirley, and Kallen.","TWN":"但實際上，在這當中只有我、 夏麗和卡蓮是真的阿什弗德學生會成員。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"미나, 너를 포함한 다른 네 사람은 애쉬포드 학원과는 전혀 관계없는 사람이지.","JPN":"ミナ、お前を含めて残りの4人は\\nアッシュフォード学園とは全く関係のない人間だ。","ENG":"The remaining four, which also includes you, Mina, have nothing to do with Ashford.","TWN":"米娜，包括你在內的其餘四個人，與阿什弗德學院一點關係也沒有。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"무슨 헛소리야!? 우리가 애쉬포드 학생이 아니라면……","JPN":"何バカなこと言ってるの！？\\n私たちがアッシュフォード学園の生徒じゃないなら……","ENG":"What are you talking about?! If we're not Ashford students, then...","TWN":"你在胡說什麼！？我們不是阿什弗德的學生的話……"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"아니라면…… 어, 어라? 아니었던 것 같기도 하고……!?","JPN":"じゃないなら……あ、あれ？　じゃなかったような……！？","ENG":"Then... H-huh? Maybe I really wasn't...?!","TWN":"的話……嗯？好像真的不是欸……！？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"읏, 머리가…… 머리가 울리는 군요.","JPN":"ううっ、頭が……頭が痛いですね。","ENG":"Ngh, my head... It's throbbing.","TWN":"唔，我的頭……嗡嗡作響。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼 애쉬포드 학원이라는 곳이 실제로 존재했단 말이야? 너희는 그곳 학생이고?","JPN":"じゃあ、アッシュフォード学園は実際に存在していたってことなの？\\nあなたたちはそこの生徒だったの？","ENG":"Then Ashford Academy is a place that really exists? And you are all students attending there?","TWN":"所以意思是阿什弗德學院是真實存在的嗎？你們是那裡的學生？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"아아, 애쉬포드 학원은 우리들이 살던 세계에 실제로 있는 곳이야.","JPN":"ああ……そうだ。\\nアッシュフォード学園は、俺たちのいた世界に実在した。","ENG":"Yes. Ashford is a real place back in my world.","TWN":"阿什弗德學院在我們生活的世界裡是真實存在的。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"를르슈가 있던 세계…….","JPN":"ルルーシュたちの世界……","ENG":"Back in Lelouch's world...","TWN":"魯路修生活的世界……"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"그래. 너희와 우리는 애초에 있었던 세계가 다르지.","JPN":"そうだ。\\n俺たちとミナたちでは、そもそも存在していた世界が違う。","ENG":"Correct. You and I are from different worlds.","TWN":"沒錯，我們和你們原本就是完全不同世界的人。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"그러니까 나는 몇번이고 반복되는 전야제에서 조금씩 변화를 만들어가며 너희를 관찰했다.","JPN":"だから、俺は何度も繰り返される<color=#ffd34c>学園祭の前日</color>に、\\n少しずつ変化を作り出してお前たちを観察した。","ENG":"That's why I observed you all while making slight changes to the ever-repeating festival preparation.","TWN":"所以我在每次重複過這一天時，都會刻意做些變化，再觀察你們。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"그리고 마침내 발견했지. 나와 마찬가지로 이 반복되는 루프를 눈치챈 사람을.","JPN":"そうして、見つけたんだ。俺のように、このループに気づいた人間を。","ENG":"And finally, I found someone. Someone who has also noticed the loop.","TWN":"於是才終於發現，有人和我一樣察覺到這一天不斷重複上演。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그렇군요, 그 사람이 바로 미나 양이겠군요.","JPN":"なるほど。それがミナさんだったのですね。","ENG":"I see. And that person is Mina.","TWN":"原來如此，那個人就是米娜吧？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"그래, 몇 번인가 루프를 반복하면서 <color=#ffd34c>데자뷰</color>를 느끼는 것 같더군.","JPN":"ああ。何度目かのループで「気付き」の兆候があったからな。","ENG":"Yes. Loop after loop, it seemed like she was experiencing <color=#ffd34c>deja vu</color>.","TWN":"沒錯，在幾次的重複中，她似乎感覺到<color=#ffd34c>既視感</color>。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"미나 역시 이 현상에 휘말린 피해자라고 가정하면, 남은 세 사람 중에서도 미나와 <color=#ffd34c>진짜 친구</color>가 있을 거라고 생각했어.","JPN":"ミナも同じくこの現象に巻き込まれた被害者だと仮定すると、\\n残りの3人の中にミナの<color=#ffd34c>本当の友達</color>がいる可能性もあると判断した。","ENG":"Assuming that Mina is also a victim here, I figured that she would also have <color=#ffd34c>true friends</color> among the other three people.","TWN":"假設米娜也是這個現象的受害者，那其餘的三個人之中，\\n應該也有米娜<color=#ffd34c>真正的朋友</color>。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"따라서 이레귤러를 구별하기 위해서 미나의 기억을 되돌리고, 진짜 친구를 떠올릴 수 있게끔 상황을 연출할 필요가 있었지.","JPN":"したがってイレギュラーを分別するためにミナの記憶を取り戻して、\\n本当の友達を思い出せるような状況を作る必要があった。","ENG":"So, in order to find the Irregular, I needed Mina to retrieve her lost memories and create situations where she would unconsciously think of her true friends.","TWN":"所以為了分辨不規律，就必須創造出一個情境，讓米娜恢復記憶，想起真正的朋友。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_PRIDE"}}}},{"id":"L47_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"그렇구나. 그러니까 지금까지 의도적으로 사고를 만들었다는 거지?","JPN":"そうか。だから、意図的にトラブルが起こるようにしていたのね。","ENG":"Right. And that's why you intentionally created problems.","TWN":"原來是這樣，所以你是故意製造出那些問題的嗎？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_PRIDE"}}}},{"id":"L49_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"즉…… 지금까지 학원제를 방해하던 범인은…… 를르슈 당신이군요.","JPN":"つまり……今まで学園祭を邪魔していた犯人はルルーシュ、あなただった。","ENG":"In other words... the culprit who was trying to stop the festival was... you, Lelouch.","TWN":"這就表示……一直在破壞學園祭的犯人就是……魯路修。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"맞아, 를르슈의 계획대로 기억을 되찾은 나는 를르슈에게 내 진짜 친구들이 누군지 알려줬어.","JPN":"そう。そのルルーシュの計画どおりに記憶を取り戻した私は、\\nルルーシュに私の本当の友達を教えたの。","ENG":"Yes, but as Lelouch planned, I was able to recover my memories and tell him who my true friends were.","TWN":"沒錯， 我按照魯路修的計畫找回記憶後，就告訴他誰是我真正的朋友。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나이엘에게 들키지 않도록 최대한 돌려서 말이야.","JPN":"ナイエルに気づかれないように、遠回しな言い方でね。","ENG":"But while keeping it a secret from Naielle.","TWN":"而且還必須不讓奈爾發現。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"뭐!? 나한테? 왜 거기서 내가 나와……? 나는 아무것도…….","JPN":"え？　私に？　どうして、そこで私が……？\\n私は何もして……","ENG":"What?! Me? What's this got to do with me...? I didn't do anything...","TWN":"蛤！？不讓我發現！？這時候怎麼扯到我……？我又沒做什……"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하지만 결과가 안 좋았다고 해서 우리끼리 탓하면서 싸우고 싶지는 않아.","JPN":"でも、結果が良くなかったからって、\\nお互いのせいにしてケンカなんてしたくない。","ENG":"But that doesn't mean we should hold each other responsible for the bad outcomes.","TWN":"但我不希望因為結果不如預期，我們就互相責怪、爭吵。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"왜냐하면…… 학원제 같이 특별한 날이 아니더라도, 우리는 <color=#ffd34c>원래부터 진짜 친구잖아. 안 그래 회장? 나이엘?</color>","JPN":"だって……学園祭みたいな特別なイベントがなくても、\\n私たちは<color=#ffd34c>元から本当の友達じゃない。そうでしょ、会長？　ナイエルも。</color>","ENG":"Because... whether or not it's a special occasion like the school festival, <color=#ffd34c>we're still true friends. Isn't that right, Yen? Naielle?</color>","TWN":"因為……就算沒有學園祭，<color=#ffd34c>我們本來就是朋友不是嗎？會長？奈爾？</color>"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"이걸로 모든 조건은 클리어 되었지.","JPN":"これで条件はすべてクリアされた。","ENG":"All tasks at hand have been cleared.","TWN":"這樣一來就滿足所有條件。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"애쉬포드 학생회 멤버도 아니고, 미나의 친구도 아닌 이레귤러는 단 한 사람.","JPN":"アッシュフォード学園の生徒会メンバーでもなく、\\nミナの仲間でもないイレギュラーはたった一人。","ENG":"There's only one Irregular who's neither a member of Ashford nor Mina's friend.","TWN":"既不是阿什弗德學生會的成員，也不是米娜朋友的人，就只有一個。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"그래, 오직 너만이 어디에도 속하지 않는 이질적인 존재다, 타피르!","JPN":"そう、お前だけがどこにも属さない異質な存在だ、タピル！","ENG":"You are the only one who doesn't belong anywhere, Tapir!","TWN":"是的，就只有你不屬於任何一方，是突兀的存在，達爾！"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"정답입니다. 용케도 여기까지 도달했군요.","JPN":"正解です。よくここまでたどり着きましたね。","ENG":"You're right. I'm impressed you managed to reach that conclusion.","TWN":"答對了，你還真是費了好大的功夫呢。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"잠깐! 다들 내 말 무시하지 마!","JPN":"ちょっと待ってよ！　みんな私のことを無視しないで！","ENG":"Wait! Don't just ignore me!","TWN":"喂！不准無視我！"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"대체 이게 뭐가 어떻게 돌아가는 건데? 왜 나를 따돌리는 거야?","JPN":"いったい何がどうなってるの？　なんで私だけのけ者にするの！？","ENG":"Just what the heck's going on here? Why's everyone ignoring me?","TWN":"這到底是怎麼回事？誰來跟我解釋一下？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"아니요, 나이엘 양. 이곳에서는 누구도 당신을 무시할 수 없어요.","JPN":"いいえ、ナイエルさん。ここでは誰もあなたをのけ者にできません。","ENG":"That's not it, Naielle. Nobody can ignore you here.","TWN":"不，奈爾，這裡沒有人可以無視你。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"왜냐하면 이 곳은 나이엘 양이 주인공이 될 수 있는 이상적인 꿈의 세계이니까요.","JPN":"なぜならここは、ナイエルさんが主人公になれる理想の夢の世界ですから。","ENG":"That's because in this dreamlike world, you are the heroine, Naielle.","TWN":"因為這裡是夢裡的理想世界，而你可以成為這個世界的主角。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"뭐, 뭐라고……!? 내가 주인공……?","JPN":"な、何ですって？　私が主人公……？","ENG":"W-what...?! I'm the heroine...?","TWN":"什，什麼……！？我是主角……？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"이곳은 세계와 세계의 <color=#ffd34c>틈새</color>.","JPN":"ここは世界と世界の<color=#ffd34c>狭間</color>。","ENG":"This place is the <color=#ffd34c>gap</color> between worlds.","TWN":"這裡是世界與世界之間的<color=#ffd34c>縫隙</color>。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"원래라면 존재 자체가 허용되지 않는 공간, 그러나 두 세계의 차원계면을 동시에 융해시켜 버릴 정도의 에너지로 인해, 일시적으로 형성된 차원간 공간입니다.","JPN":"本来なら存在自体が許されない空間ですが、2つの世界の次元界面を\\n同時に融解させてしまうほどの莫大なエネルギーによって、一時的に形成された次元間空間です。","ENG":"It is typically a space that shouldn't exist at all. But, because of the enormous inflow of energy that could fuse the dimension surface of the two worlds, it has been temporarily formed.","TWN":"原本是不該存在的空間，是由於足以同時融化二個世界次元界面的能量，才暫時產生的次元間空間。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"차원을 융해시킬 만큼의 에너지라고……?","JPN":"次元を融解させるほどのエネルギーだって……？","ENG":"An energy large enough to fuse dimensions...?","TWN":"足以融化次元的能量……？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"설마, 스자쿠가 쐈던 그 전략병기를 말하는 건가?","JPN":"まさか、スザクが撃ったあの戦略兵器のことか？","ENG":"Perhaps, the strategic warhead that Suzaku fired...","TWN":"難道你是指朱雀發射的戰略武器嗎？"},"stage":{"bg":"GEASS_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"그렇습니다. 그리고 이렇게 만들어진 차원간 공간은 강력한 정신오염 지대를 형성합니다.","JPN":"そうです。そして、このようにして作られた次元間空間は、\\n強力な精神汚染地帯を形成します。","ENG":"Correct. And within the dimensional plain that was formed, a potent mind-polluting zone was created.","TWN":"沒錯，於是如此產生的次元間空間形成強烈的精神汙染地帶。"},"stage":{"bg":"GEASS_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"따라서 이곳이라면 인간의 무의식을 실체화하여 현실에는 존재하지 않는 이상적인 꿈의 세계를 구현할 수 있죠.","JPN":"ですので、ここなら人間の無意識を実体化し、\\n現実にはない理想の夢の世界を具現化することができます。","ENG":"Therefore, this place can realize the human unconsciousness and create an idealized, dreamlike world.","TWN":"因此在這個空間裡，可以將人類的潛意識\\n具體化，創造出一個不存在於現實中的理想世界。"},"stage":{"bg":"GEASS_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"리플레이서 킹과 싸웠던 때와 비슷한…… 심상세계란 말이야?","JPN":"リプレイサー・キングと戦った時と似ている……\\n心の世界ということなの？","ENG":"You mean... the mental world? Like when I fought Replacer King?","TWN":"跟我和克隆·帝皇交手時很類似的……內心世界？"},"stage":{"bg":"GEASS_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐 너는 애쉬포드 학생회가 아니라면서, 그런데 어떻게 애쉬포드 학원을 실체화한 거야?","JPN":"待って、あなたは生徒会メンバーではないのに、\\nどうやってアッシュフォード学園を実体化したの？","ENG":"Wait, you're not even a member of the Student Council at Ashford. So how did you replicate Ashford Academy?","TWN":"不對，你又不是阿什弗德學生會的成員，為什麼要將阿什弗德學院具體化？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"뭔가 착오가 있군요, 미나 양.","JPN":"何か勘違いをしていますね、ミナさん。","ENG":"You misunderstand, Mina.","TWN":"米娜，你好像哪裡誤會了。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"기계는 꿈을 꿀 수 없습니다. 다시 말해, 이 꿈의 세계를 유지하는 동력원은 오롯이 당신들의 무의식이죠.","JPN":"機械は夢を見ることができません。\\nつまり、この夢の世界を維持している動力源は、あなたたちの無意識です。","ENG":"Machines do not dream. In other words, your unconsciousness is the only source of this dream world.","TWN":"機器是無法作夢的，我再說一次，能夠讓這個夢裡的世界持續下去的動力，是來自於你們的潛意識。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"제 본체는 당신들의 무의식을 <color=#ffd34c>조율</color>하면서 학원제의 전날을 시뮬레이션 하고 있을 뿐입니다.","JPN":"僕の本体はあなたたちの無意識を<color=#ffd34c>調整</color>しながら\\n<color=#ffd34c>学園祭の前日</color>をシミュレーションしていただけに過ぎません。","ENG":"All my mainframe is doing is <color=#ffd34c>adjusting</color> your unconsciousness and simulating the day before the festival.","TWN":"而我只是<color=#ffd34c>調整</color>你們的潛意識，同時模擬學園祭的前一天而已。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하, 학원제라고? 대체 왜그렇게까지 학원제에 집착하는 건데?","JPN":"が、学園祭？　どうしてそんなに学園祭に執着するの？","ENG":"F-festival? But why are you so obsessed with the festival, anyway?","TWN":"什麼？學園祭？你為什麼要這麼執著於學園祭？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"질문의 의도를 알 수 없군요, 미나 양.","JPN":"質問の意図がわかりませんね、ミナさん。","ENG":"I don't understand the intent of your question, Mina.","TWN":"我不懂這個問題的重點是什麼。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"이건 제가 집착하는 게 아닙니다. 이건 당신들이 바란 꿈의 교집합이죠.","JPN":"これは僕の執着ではありません。\\nこれはあなたたちが望んだ夢の集合体です。","ENG":"None of this is my obsession. It is an intersection of all your desires and wishes.","TWN":"不是我執著於學園祭，這是你們願望的集合體。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"꿈의 교집합?","JPN":"夢の集合体？","ENG":"An intersection of our desires and wishes?","TWN":"願望的集合體？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"누군가에게는 마음의 안식처를…….","JPN":"ある人は心の安息の場所を……","ENG":"For some, to visit a place of comfort...","TWN":"對某人而言，需要心靈的安息……"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"누군가에게는 돌아올 수 없는 일상을…….","JPN":"ある人は戻らない日常を……","ENG":"For others, to relive the everyday life that will never come back...","TWN":"對某人而言，是回不去的日常……"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"또 누군가는 타인에게 헌신하거나…… 혹은 페스티벌의 주인공이 되기 위해……","JPN":"またある人は他人に献身したり……あるいはフェスティバルの主人公になるために……","ENG":"To devote oneself to others... Or to become the star of the festival...","TWN":"或是想為他人犧牲奉獻……又或者是想成為慶典的主角……"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"그리고 누군가는…… 잃어버린 학창 시절의 아련한 기억 때문에.","JPN":"そして別の誰かは……なくした学生時代のおぼろげな記憶のために。","ENG":"And for someone... to reminisce about the long-gone days of school.","TWN":"甚至是某人……對於學生時期的模糊印象。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"각자 사정은 다르지만, 모두의 무의식 한 구석에는 학원제를 바라고 있었어요.","JPN":"それぞれの事情は異なりますが、\\nみんな無意識の片隅で学園祭を望んでいました。","ENG":"Everyone has their own reason. But you all wanted the festival to happen deep down in your hearts.","TWN":"雖然情況各不相同，但大家潛意識中的共通點就是學園祭。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"전 누구도 실망하지 않는 학원제를 만들어내기 위하여 계속해서, 계속해서…… 오늘을 반복해온 겁니다.","JPN":"僕は誰もガッカリしない学園祭を作り上げるためにずっと、\\nずっと……今日を繰り返してきたのです。","ENG":"I've been attempting to create a festival that leaves no one disappointed, repeating the same day over and over...","TWN":"我為了創造出一個讓所有人都滿意的學園祭，所以才不斷地……重複今天。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"들을 가치도 없는 헛소리군요.","JPN":"聞く価値もない戯言ですね。","ENG":"This is nonsense.","TWN":"我剛才聽了什麼？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"말도 안돼! 해도 되는 일이 있고, 해서는 안 되는 일이 있는 거잖아!","JPN":"だからと言って、やっていいことと悪いことがある。","ENG":"Unbelievable! There are lines you should never cross!","TWN":"荒謬！你分不清楚什麼事可以做，什麼事不能做嗎！"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"웃기지 마! 우리 중에 누구도 그런 걸 원하지 않아!","JPN":"ふざけないで！　私たちは誰もそんなことを望んでいない！","ENG":"This is ridiculous! None of us ever wanted any of this!","TWN":"可笑！我們當中才沒有人想要這樣呢！"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"타피르 선배…….","JPN":"タピル先輩……","ENG":"Tapir...","TWN":"達爾前輩……"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"당신들이야말로 아무것도 모르는군요.","JPN":"あなたたちこそ、何もわかっていませんね。","ENG":"It's apparent that you all know nothing.","TWN":"你們什麼不懂。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"아주 오래 전, 절 만든 연구원들은 제게 인류를 구원하라는 목표를 부여했죠.","JPN":"遠い昔、僕を作った研究員たちは僕に人類を救えという目標を付与しました。","ENG":"A long time ago, the researchers that made me gave me a purpose. To save humanity.","TWN":"很久以前，創造我的研究員對我設下救贖人類的目標。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"애초부터 불가능한 목표란 건 알고 있었습니다. 연산 결과, 어떤 방법을 써도 인류는 멸망을 피할 수 없으니까요.","JPN":"最初から不可能な目標だということは知っていました。\\n演算の結果、どんな方法を使っても人類は滅亡を避けられませんでしたから。","ENG":"They knew it was an impossible task. Calculations always lead to the same conclusion: humanity will perish.","TWN":"我從一開始就知道這是個不可能的任務。\\n因為根據運算結果，沒有任何方法可以使人類免於滅亡。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"하지만 인류 구원에 실패하고……. 허수공간을 떠돌던 저는 마침내 깨닫고 만 것입니다.","JPN":"しかし、人類の救済に失敗し…… 虚数空間をさまよっていた私は、とうとう気がついてしまいました。","ENG":"Failing to save humanity... I was drifting in the imaginary space when I finally realized.","TWN":"然而救贖人類的任務失敗後……當我徘徊在虛數空間時，我終於領悟到。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"우연과 우연이 겹쳐 만들어진 이 공간…….","JPN":"偶然と偶然が重なって作られたこの空間……","ENG":"This space... created by the overlap of coincidence after coincidence...","TWN":"在偶然與偶然重疊後創造出的這個空間裡……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"시공을 초월한 이곳에 꿈의 세계를 건설한다면 인류를 구원하진 못해도…… 적어도 보존할 수는 있다는 것을 말이죠!","JPN":"時空を越えるこの場所に夢の世界を建設したら、\\n人類を救うことはできなくても……少なくとも、保存することはできるでしょう。","ENG":"A place that transcends time and space... If I could construct a dream world here, then, though I might not be able to save humanity... I could at the very least preserve it!","TWN":"若是能夠在這個超越時空的空間裡打造一個夢裡的世界，那即使無法救贖人類……至少可以使人類存留下去！"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"훗, 쓸데없는 참견이야.","JPN":"ふっ。余計なお世話だな。","ENG":"Heh, what a waste of time.","TWN":"呵，你真雞婆。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"내일 세계가 멸망한다고 해서, 변하지 않는 오늘을 반복하는 게 무슨 의미가 있지?","JPN":"明日、世界が滅亡したとして、\\n変わらない1日を繰り返して何の意味があるんだ？","ENG":"Even if the world were to end tomorrow, what meaning would there be in repeating the same day over and over again?","TWN":"因為明天世界就要滅亡，所以一直重複今天嗎？這有什麼意義？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"그저 변하지 않는 매일을 보내기만 하는 인생…… 나는 거부하겠어.","JPN":"変わらない毎日をただ生かされるだけの人生、俺は嫌だ。","ENG":"Living in a world where every day is unchanging... I refuse it.","TWN":"只能固定過同一天的人生……我才不想要！"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"원래 세계로 돌아가 봤자, 괴로운 현실만이 기다리고 있을 텐데요?","JPN":"元の世界に戻っても辛い現実だけかもしれないのに？","ENG":"Even if all reality has to offer is suffering?","TWN":"就算你回到原本的世界，等待你的也只是殘酷的現實。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L37_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"상관없다. 나에겐 반드시 현실로 돌아가야만 하는 이유가 있어.","JPN":"それでもだ。\\n俺には元の世界に戻らねばならない理由がある。","ENG":"It doesn't matter. There is a reason why I must return to reality.","TWN":"無所謂，我有我必須回到現實世界的理由。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L38_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"그걸 방해한다면…… 누구든 배제할 뿐이다!","JPN":"邪魔するのであれば……誰であれ、排除するだけだ！","ENG":"I will eliminate... anyone who gets in my way!","TWN":"要是誰敢妨礙我……我都會除之而後快！"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L39_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"말했을 텐데요, 를르슈?","JPN":"言ったはずですよ、ルルーシュ？","ENG":"Did I not tell you, Lelouch?","TWN":"魯路修，我剛應該有說過吧？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"이 공간은 당신들의 무의식으로 구축한 꿈의 세계…….","JPN":"この空間はあなたたちの無意識によって構築された夢の世界……","ENG":"This dream world is constructed by everyone's unconsciousness...","TWN":"這個空間是根據你們的潛意識而創造出的夢境……"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"설령, 이 단말을 파괴한다고 하더라도, 또 다시 학원제를 반복하면 그만입니다.","JPN":"たとえこの端末を破壊したとしても、再び学園祭は繰り返されるだけです。","ENG":"Even if you destroy this body, the festival will just repeat itself again.","TWN":"就算這次被你破壞掉，我也只需要再重複一次學園祭就好。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"를르슈! 무슨 방법이 없는거야?","JPN":"ルルーシュ！　何か良い手はないの？","ENG":"Lelouch! Is there really no way out of here?","TWN":"魯路修！你有什麼辦法嗎？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"나이엘 양. 당신에게는 특별히 감사하고 있어요.","JPN":"ナイエルさん、あなたには特別感謝しています。","ENG":"Naielle. I'm especially grateful to you.","TWN":"奈爾，我要特別感謝你。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"뭐, 뭐라구……?","JPN":"な、何よ……？","ENG":"W-what...?","TWN":"謝，謝我……？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"당신만큼은 어떤 상황에서도 변함없이 학원제를 즐겨 주셨으니까…….","JPN":"あなただけはどんな状況でも変わらず、学園祭を楽しみにしてくれましたから。","ENG":"You're the only person who truly enjoyed the festival no matter the situation...","TWN":"只有你無論在什麼情況下，都始終如一地享受在學園祭裡……"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"당신이 학원제를 완벽하게 끝내고 싶다는 그 마음이……. 이 세계를 유지하는 강력한 원동력으로 작용하고 있으니까요.","JPN":"あなたの、学園祭を完璧に成功させたい、という気持ちの強さが、\\nこの世界を維持するための強力な原動力となっている。","ENG":"Your desire to have the perfect festival... It is the driving force that maintains this world.","TWN":"你想要讓學園祭完美結束的想法……正是使這個世界得以持續下去的強大動能。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"결코 도달하지 못할 학원제 당일에 대한 그 <color=#ffd34c>열정</color>이 존재하는 한, 이 세계는 계속해서 유지될 겁니다.","JPN":"いつまでもやってこない学園祭当日にかけるあなたの<color=#ffd34c>情熱</color>がある限り、\\nこの世界は維持され続けるのです。","ENG":"As long as that <color=#ffd34c>yearning</color> for the unreachable day of the festival exists, this world will continue to exist.","TWN":"只要你對永遠無法舉行的學園祭懷抱<color=#ffd34c>熱情</color>，那這個世界就將持續下去。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"……영원히.","JPN":"……永遠に。","ENG":"...Forever.","TWN":"……到永遠。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"나이엘 양의 마음이 이 세계를 유지하고 있다고……?","JPN":"ナイエルさんの気持ちがこの世界を維持している……","ENG":"So Naielle's desire is what's keeping this world intact...?","TWN":"是奈爾的想法在維持這個世界的……？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"나이엘! 당장 학원제에 대한 미련을 버리세요!","JPN":"ナイエルさん！　今すぐ学園祭への未練を捨ててください！","ENG":"Naielle! Get rid of any lingering feelings for the festival right now!","TWN":"奈爾！立刻放下你對學園祭的執著！"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래! 나이엘! 학교 축제는 아카데미에 돌아가서도 할 수 있잖아!","JPN":"そうだよナイエル！　学園祭はアカデミーでもできるじゃない！","ENG":"Yeah, Naielle! We can have our own festival once we return to the Academy!","TWN":"是啊！奈爾！要辦慶典的話回去也可以辦啊！"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그, 그렇지만…… 그렇게 말해도…… 학원제 계속 하고 싶은 걸 어떡해……!!","JPN":"で、でも……そんなこと言われても……\\n私は学園祭がやりたいんだもん……！！","ENG":"B-but... Even if you say that... I can't help but want to have a festival every day...!","TWN":"可，可是……就算你們這麼說……人家還是很想讓學園祭繼續下去嘛，能怎麼辦……！！"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"나이엘!?","JPN":"ナイエル！？","ENG":"Naielle?!","TWN":"奈爾！？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"간신히 학년 대표가 됐는데…… 캠프파이어…… 진짜로 열심히 준비했는데…….","JPN":"ようやく学年代表になったのに……\\nキャンプファイヤーの必殺技……本当に一生懸命準備したのに……","ENG":"I was elected as this year's student representative... Even the campfire... I put so much effort in preparing it...","TWN":"我好不容易才當上學生代表……而且還那麼認真……準備營火……"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이번에야 말로…… 주인공이 될 수 있었는데……!!","JPN":"今度こそ……主人公になれたのに……！！","ENG":"And finally... It was my chance to become the star of the festival...!","TWN":"這次……我一定可以當上主角的……！！"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"정신 차려, 나이엘! 그게 저 녀석이 원하는 거잖아!","JPN":"しっかりして、ナイエル！　その考え方こそ、あいつの狙いそのものなの！","ENG":"Snap out of it, Naielle! That's exactly what he wants!","TWN":"奈爾，你清醒一點！你這樣不就讓他稱心如意了嗎！"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"소용없습니다. 인간의 마음이 그리 쉽게 변할 리 없죠.","JPN":"無駄です。人間の心はそう簡単に変わりません。","ENG":"It's pointless. A person's mind is not easily swayed.","TWN":"沒用的，人類的想法是沒那麼容易改變的。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L21_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"자, 나이엘 양, 이번에야 말로 바라는 겁니다. 한 점의 후회 없는 완벽한 학원제를……!","JPN":"さあ、ナイエルさん。今度こそ切実に願ってください。\\n一切の後悔のない完璧な学園祭を……！","ENG":"Now, Naielle. It's time to make your wish. For the perfect festival...!","TWN":"來吧，奈爾，這次很有希望，你想要的毫無缺憾完美學園祭……！"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"우으…….","JPN":"うう……","ENG":"Err...","TWN":"唔……"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"……가능하면, 이 방법은 쓰고 싶지 않았지만.","JPN":"……出来ることなら、この手は使いたくなかった。","ENG":"...I have no choice but to do this.","TWN":"……可以的話，我是不太想用這個方法。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"COLLABO_2022_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L25_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"음?","JPN":"うん？","ENG":"Hmm?","TWN":"什麼？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"COLLABO_2022_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"인간이 다른 인간의 의지에 간섭하는 건, 원래라면 있어선 안 돼.","JPN":"人が人の意思を曲げるなど、本来あってはならない。","ENG":"Interfering with another person's will... It shouldn't be allowed.","TWN":"原本干涉他人的想法是不允許的。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"COLLABO_2022_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"를르슈?","JPN":"ルルーシュ？","ENG":"Lelouch?","TWN":"魯路修？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"COLLABO_2022_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"하지만 그 의지를…… 그 열정을 계속해서 이용당하는 건 다른 문제야.","JPN":"しかし、その意思を、情熱を利用され続けるのも間違いだ。","ENG":"But if her will, if her yearning is being manipulated... That's another problem entirely.","TWN":"但要是那個想法……那份熱情，一直遭到利用，那就另當別論了。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"COLLABO_2022_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"그래, 를르슈에게는 <color=#ffd34c>그 힘</color>이 있어.","JPN":"そうか。そうだよね。ルルーシュには、その力がある。","ENG":"Oh, right. Lelouch has <color=#ffd34c>that ability</color>.","TWN":"沒錯，憑魯路修的<color=#ffd34c>力量</color>可以辦得到。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"COLLABO_2022_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그 힘이라고요……?","JPN":"その力って……","ENG":"Ability...?","TWN":"什麼力量……？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"COLLABO_2022_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"그러니까 나는 기꺼이 행하겠다! 악으로 정의를……!","JPN":"だから、俺は為そう。悪をもって正義を！","ENG":"So I will gladly act! I will execute justice with evil...!","TWN":"我很樂意用惡來實現正義……！"},"stage":{"bg":"GEASS_ASHFORD","bgm":"COLLABO_2022_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"무슨 짓을 할 셈입니까, 를르슈!?","JPN":"何をするつもりだ、ルルーシュ！？","ENG":"What are you doing, Lelouch?!","TWN":"你想做什麼，魯路修！？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"COLLABO_2022_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"사람의 무의식을 읽어내는 너라도, 나의 능력을 파악하는 것은 불가능한 모양이로군.","JPN":"人の意識を読み取るお前でも、\\n俺のこの能力を把握することは出来なかったようだな。","ENG":"Even if you can read a person's unconsciousness, it seems that it's impossible for you to grasp what my ability is.","TWN":"看來就算你可以讀取人的潛意識，卻無法掌握我的能力。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"COLLABO_2022_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"나에게는 어떤 상대에게도 한 번, 명령을 내릴 수 있는 절대복종의 힘이 있다.","JPN":"俺には、いかなる相手にでも一度だけ命令を下せる絶対遵守の力がある。","ENG":"I have the ability to command anyone once with the power of absolute obedience.","TWN":"我有可以對任何人下令一次的絕對服從之力。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"COLLABO_2022_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"명령? 설마 화학 선생님과 연극부 부장이 이상한 행동을 했던 것도…….","JPN":"命令？\\nまさか科学の先生や演劇部の部長の言動がおかしかったのも……","ENG":"Command? Is that why the chemistry teacher and the theater club leader were acting weird...?","TWN":"下令？難道化學老師和戲劇部社長的異常行為也是因為……"},"stage":{"bg":"GEASS_ASHFORD","bgm":"COLLABO_2022_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"맞아. 를르슈의 힘…… 기아스에는 저항할 수 없어. 설령 본인의 의지를 꺾는 일이라고 해도.","JPN":"そう。ルルーシュのあの力……、ギアスには誰も逆らえない。\\n例え、それが本人の意思を捻じ曲げることだったとしても。","ENG":"Yes. Lelouch's power, Geass... No one can resist it. Even if it means breaking one's own will.","TWN":"沒錯，魯路修的力量……沒有人能夠抵抗Geass，即使那違背本人的意願。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"COLLABO_2022_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"서, 설마 그 힘으로 나이엘 양을……!?","JPN":"ま、まさか、その力を使ってナイエルの……","ENG":"Y-you're going to use that on Naielle...?!","TWN":"所以，你要用那股力量對奈爾……！？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"COLLABO_2022_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"정답이다, 타피르.","JPN":"正解だ。タピル。","ENG":"Correct, Tapir.","TWN":"答對了，達爾。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"COLLABO_2022_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"를르슈 비 브리타니아가 명한다.","JPN":"ルルーシュ・ヴィ・ブリタニアが命じる。","ENG":"I, Lelouch vi Britannia, command you.","TWN":"魯路修·Vi·不列顛尼亞在此命令。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"COLLABO_2022_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"<color=#ff3636>나이엘, 거짓된 학원제를 부정해라!</color>","JPN":"<color=#ff3636>ナイエルよ、偽りの学園祭を否定しろ！</color>","ENG":"<color=#ff3636>Naielle, reject the false festival!</color>","TWN":"<color=#ff3636>奈爾，拒絕假的學園祭！</color>"},"stage":{"bg":"GEASS_ASHFORD","bgm":"COLLABO_2022_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_COMBAT_ALL_SKILL_START"}]`);export{e as default};